#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        char **grid = (char**)malloc(N*sizeof(char*));
        for(int i=0;i<N;i++){
            grid[i]= (char*)malloc((M+1)*sizeof(char));
            scanf("%s", grid[i]);
        }
        int Q; scanf("%d", &Q);
        // allocate diff array with extra row and column
        int **diff = (int**)calloc(N+2, sizeof(int*));
        for(int i=0;i<N+2;i++) diff[i]= (int*)calloc(M+2, sizeof(int));
        for(int k=0;k<Q;k++){
            int x1,y1,x2,y2; scanf("%d %d %d %d", &x1,&y1,&x2,&y2);
            diff[x1][y1] ^= 1;
            diff[x1][y2+1] ^= 1;
            diff[x2+1][y1] ^= 1;
            diff[x2+1][y2+1] ^= 1;
        }
        // prefix xor over rows
        for(int i=1;i<=N;i++){
            for(int j=1;j<=M;j++){
                diff[i][j] ^= diff[i-1][j] ^ diff[i][j-1] ^ diff[i-1][j-1];
            }
        }
        // output result
        for(int i=0;i<N;i++){
            for(int j=0;j<M;j++){
                int flip = diff[i+1][j+1];
                char c = grid[i][j];
                if(flip) c = (c=='0')?'1':'0';
                putchar(c);
            }
            putchar('\n');
        }
        // free memory
        for(int i=0;i<N;i++) free(grid[i]);
        free(grid);
        for(int i=0;i<N+2;i++) free(diff[i]);
        free(diff);
    }
    return 0;
}

